import React, { createContext, useState, useEffect, useContext, useCallback } from 'react';
import authService, { setLogoutCallback } from '../services/authService';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const logout = async () => {
    try {
      await authService.logout();
    } catch (error) {
      console.error('Erro no logout:', error);
    } finally {
      setUser(null);
      setIsAuthenticated(false);
    }
  };

  const loadUserProfile = useCallback(async () => {
    console.log('[AuthContext] Carregando perfil completo do usuário...');
    try {
      const profileResponse = await authService.getProfile();
      console.log('[AuthContext] Perfil carregado:', profileResponse.user);

      if (profileResponse && profileResponse.user) {
        setUser(profileResponse.user);
        return profileResponse.user;
      }
    } catch (error) {
      console.error('[AuthContext] Erro ao carregar perfil:', error);
    }
    return null;
  }, []);

  const checkAuthStatus = useCallback(async () => {
    console.log('[AuthContext] Iniciando verificação de autenticação...');
    try {
      const response = await authService.checkSession();
      console.log('[AuthContext] Resposta da verificação:', response.data);

      if (response.data && response.data.logged_in && response.data.user) {
        console.log('[AuthContext] Usuário autenticado, carregando perfil completo...');
        setUser(response.data.user);
        setIsAuthenticated(true);

        // Carregar perfil completo após verificar sessão
        await loadUserProfile();
      } else {
        console.log('[AuthContext] Usuário não autenticado');
        setIsAuthenticated(false);
      }
    } catch (error) {
      console.error('[AuthContext] Erro ao verificar autenticação:', error);
      setIsAuthenticated(false);
    } finally {
      console.log('[AuthContext] Finalizando verificação, setLoading(false)');
      setLoading(false);
    }
  }, [loadUserProfile]);

  useEffect(() => {
    console.log('[AuthContext] Componente montado, iniciando verificação...');

    // Registrar callback de logout no interceptador
    setLogoutCallback(() => {
      setUser(null);
      setIsAuthenticated(false);
    });

    checkAuthStatus();
  }, [checkAuthStatus]);

  const login = async (email, password) => {
    console.log('[AuthContext] Iniciando login para:', email);
    try {
      const response = await authService.login({ email, password });
      console.log('[AuthContext] Resposta do login:', response.data);

      if (response.data && response.data.user) {
        console.log('[AuthContext] Login bem-sucedido, carregando perfil completo...');
        setUser(response.data.user);
        setIsAuthenticated(true);

        // Carregar perfil completo após login
        await loadUserProfile();

        return { success: true };
      }
      console.log('[AuthContext] Login falhou - dados inválidos');
      return { success: false, message: 'Credenciais inválidas' };
    } catch (error) {
      console.error('[AuthContext] Erro no login:', error);
      return { success: false, message: error.message || 'Erro no login' };
    }
  };

  const value = {
    user,
    loading,
    isAuthenticated,
    login,
    logout,
    checkAuthStatus,
    loadUserProfile
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

export { AuthContext };
export default AuthContext;
